import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, Navigate, useNavigate } from 'react-router-dom';
import Login from './authentication/Login';
import Register from './authentication/register';
import Dashboard from './components/Dashboard';
import UserProfile from './components/UserProfile';
import ProductList from './components/ProductList';
import ShoppingCart from './components/ShoppingCart';
import SearchBar from './components/SearchBar';
import AdminPanel from './components/AdminPanel';
import ErrorBoundary from './components/ErrorBoundary';
import NotificationCenter from './components/NotificationCenter'; 
import { AppProvider, useAppContext } from './context/AppContext';
import OrderHistory from './components/OrderHistory';
import { fetchUserCartFromServer, syncUserCartToServer } from './utils/api';
import './styles/App.css';

// =========================================================================
// 🔒 GLOBAL ROUTE GUARD WRAPPER (Strict Tab-Isolated Security)
// =========================================================================
function ProtectedAdminRoute({ children }) {
  const cachedSession = sessionStorage.getItem("currentUser");
  if (!cachedSession) {
    return <Navigate to="/login" replace />;
  }

  try {
    const sessionObj = JSON.parse(cachedSession);
    const isValidAdmin = 
      sessionObj && 
      sessionObj.role === "admin" && 
      sessionObj.token && 
      sessionObj.token.startsWith("admin-secure-session");

    if (!isValidAdmin) {
      return <Navigate to="/login" replace />;
    }
  } catch (e) {
    sessionStorage.removeItem("currentUser");
    return <Navigate to="/login" replace />;
  }

  return children;
}

function App() {
  const [user, setUser] = useState(null);
  const [cart, setCart] = useState([]);
  const [theme, setTheme] = useState("light");
  const [isConfigLoading, setIsConfigLoading] = useState(true); 
  const navigate = useNavigate(); 

  // Handle application initialization state loading routines
  useEffect(() => {
    const savedUser = sessionStorage.getItem("currentUser");
    if (savedUser) {
      try {
        const parsedUser = JSON.parse(savedUser);
        
        if (
          parsedUser.role === "admin" && 
          (!parsedUser.token || !parsedUser.token.startsWith("admin-secure-session"))
        ) {
          sessionStorage.removeItem("currentUser");
          setUser(null);
        } else {
          setUser(parsedUser);
        }
      } catch (e) {
        console.error(e);
        sessionStorage.removeItem("currentUser");
      }
    }
    setIsConfigLoading(false); 
  }, []);

  // Fetch cart automatically on user login
  useEffect(() => {
    if (user && user.name) {
      fetchUserCartFromServer(user.name.toLowerCase()).then(cloudCart => {
        if (cloudCart && cloudCart.items) {
          setCart(cloudCart.items);
        }
      }).catch(err => {
        console.error("Cart retrieval protection active:", err);
        setCart([]);
      });
    } else {
      setCart([]);
    }
  }, [user]);

  function handleLogin(userData) {
    setUser(userData);
    sessionStorage.setItem("currentUser", JSON.stringify(userData));
  }

  function handleLogout() {
    setUser(null);
    sessionStorage.removeItem("currentUser");
  }

  // ==========================================
  // CORE CART STATE MANIPULATION FUNCTIONS
  // ==========================================
  function addToCart(item) {
    if (!user || !user.name) {
      alert("🔒 Authentication Required: Please log into your store profile account to append items to your shopping cart!");
      navigate("/login");
      return;
    }

    setCart(prevCart => {
      const existingItem = prevCart.find(i => i.id === item.id);
      let updatedCart;

      if (existingItem) {
        updatedCart = prevCart.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      } else {
        updatedCart = [...prevCart, { ...item, quantity: 1 }];
      }

      syncUserCartToServer(user.name.toLowerCase(), updatedCart);
      return updatedCart;
    });
  }

  function updateQuantity(id, newQuantity) {
    if (!user || !user.name) return;
    setCart(prevCart => {
      const updatedCart = prevCart.map(item => item.id === id ? { ...item, quantity: Math.max(1, newQuantity) } : item);
      syncUserCartToServer(user.name.toLowerCase(), updatedCart);
      return updatedCart;
    });
  }

  function removeFromCart(id) {
    if (!user || !user.name) return;
    setCart(prevCart => {
      const updatedCart = prevCart.filter(item => item.id !== id);
      syncUserCartToServer(user.name.toLowerCase(), updatedCart);
      return updatedCart;
    });
  }

  if (isConfigLoading) {
    return (
      <div style={{ padding: "50px", textAlign: "center", fontFamily: "sans-serif" }}>
        <h2>Loading secure application configuration profiles...</h2>
      </div>
    );
  }

  return (
    <AppProvider>
      <ErrorBoundary>
        <div className={`app ${theme}`}>
          <nav className="navbar" style={{ display: "flex", gap: "15px", padding: "15px", background: "#007bff", alignItems: "center" }}>
            <Link to="/" style={{ color: "#fff", textDecoration: "none" }}>Home</Link>
            <Link to="/products" style={{ color: "#fff", textDecoration: "none" }}>Products</Link>
            <Link to="/cart" style={{ color: "#fff", textDecoration: "none" }}>Cart ({cart.reduce((total, item) => total + item.quantity, 0)})</Link>
            <Link to="/search" style={{ color: "#fff", textDecoration: "none" }}>Search</Link>
            
            {user ? (
              <>
                <Link to="/dashboard" style={{ color: "#fff", textDecoration: "none" }}>Dashboard</Link>
                <Link to={`/profile/${user.id || "me"}`} style={{ color: "#fff", textDecoration: "none" }}>Profile</Link>
                
               // ===================================================================================
// 🛠️ THE NAVIGATION ROUTING FIX: Overwrite line 178 inside src/App.js with this copy
// ===================================================================================
<Link 
  to={`/orders/${(user.name || user.username || "").toLowerCase()}`} 
  style={{ color: "#fff", textDecoration: "none" }}
  onClick={() => {
    // Force direct cache invalidation download cycles on page changes
    setTimeout(() => window.location.reload(), 50);
  }}
>
  Orders
</Link> 
                {user.role === "admin" && user.token && user.token.startsWith("admin-secure-session") && (
                  <Link to="/admin" style={{ color: "#ffc107", fontWeight: "bold", marginLeft: "10px", textDecoration: "none" }}>Admin</Link>
                )}
                <button onClick={handleLogout} style={{ marginLeft: "auto", cursor: "pointer", background: "#dc3545", color: "#fff", border: "none", padding: "6px 12px", borderRadius: "4px" }}>Logout</button>
              </>
            ) : (
              <Link to="/login" style={{ marginLeft: "auto", color: "#fff", textDecoration: "none" }}>Login</Link>
            )}
          </nav>

          <main>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={<Login onLogin={handleLogin} />} />
              <Route path="/register" element={<Register />} />
              <Route path="/dashboard" element={<Dashboard user={user} />} />
              <Route path="/profile/:id" element={<UserProfile />} />
              <Route path="/products" element={<ProductList addToCart={addToCart} />} />
              
              <Route path="/cart" element={
                <ShoppingCart cartItems={cart} updateQuantity={updateQuantity} removeFromCart={removeFromCart} />
              } />
              
              <Route path="/search" element={<SearchBar addToCart={addToCart} />} />
              
              {/* ✅ ROUTING CRITICAL FIX: Updated router mapping target with dynamic name tokens */}
              <Route path="/orders/:username" element={<OrderHistory user={user} />} />

              <Route path="/admin" element={
                <ProtectedAdminRoute>
                  <AdminPanel user={user} />
                </ProtectedAdminRoute>
              } />
            </Routes>
          </main>

          <NotificationCenter />
        </div>
      </ErrorBoundary>
    </AppProvider>
  );
}

function Home() {
  const [count, setCount] = useState(0);
  const { state = { user: null } } = useAppContext();

  useEffect(() => {
    const timer = setInterval(() => { setCount(c => c + 1); }, 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="home" style={{ padding: "30px", textAlign: "center" }}>
      <h1>Welcome {state?.user?.name ? ", " + state.user.name : ""}!</h1>
      {count > 0 && <p>You have been here for {count} seconds</p>}
    </div>
  );
}

export default App;
